#' Ingest BP data to prepare for iCe
#'
#' This function reads in a dataset of points (relative time x relative blood pressure) extracted from a pdf (generated by EndoPat by Itamar)
#'
#' @param x csv file with two columns: relative time and relative BP
#'
#' @return data2 -- data table for use in calcLocalMax
#' @export read_data
#'
#' @import dplyr
#'
#' @examples read_data("data.csv")
read_data <- function(x) {

  wd <- getwd()
  data <- read.csv(paste0(wd, "/", x), header=FALSE)

  setnames(data, 'V1', 'Relative_time')
  setnames(data, 'V2', 'Pressure')

  #class(data$Pressure)

  data2 <<- as.data.table(data)

  plot(data2)
}

#' Calculate the Local Maxima of a Dataset
#'
#' This function serves to calculate all the local maxima of a dataset or, if the data is first multiplied by -1 in the input, the local minima
#'
#' @param x the dataset contaiing the dependent variable of the data set for which you want the maxima
#'
#' @return y -- vector of row numbers which describe local maxima
#' @export localMaxima
#'
#' @examples Output <- localMaxima(datatable$dependentvariable)
localMaxima <- function(x) {
  # Use -Inf if x is numeric
  y <- diff(c(-.Machine$integer.max, x)) > 0L #get max negative integer and add as value 1, then calculate diff between each column, then create boolean if value is positive/negative
  rle(y)$lengths #included just for debug to ensure the run-length encoding runs ok even though repeated below
  y <- cumsum(rle(y)$lengths) #rle to get run-length encoding to count number of values between maxima and cumsum to add space between maxima to get row numbers where maxima are found
  y <- y[seq.int(1L, length(y), 2L)] #rle has all the "1" next to count so take every other number to remove these
  if (x[[1]] == x[[2]]) {
    y <- y[-1]
  }
  y #drop first row remaining from appending max integer
}

#' Execute the localMaxima Function
#'
#' This function uses the localMaxima function to assess the data table created by read_data
#'
#' @param x Datatable of relative time x relative pressure
#'
#' @return MaximaRows -- Dataset of selected local maxima in ingested datatable
#' @export calcLocalMax
#'
#' @examples calcLocalMax(data2)
calcLocalMax <- function(x) {
  x <- x[order(Relative_time)]
  LocalMaxima <- localMaxima(x$Pressure)
  x$link <- seq.int(nrow(x))
  MaximaRows <<- x[x$link %in% LocalMaxima, ]

  plot(y = MaximaRows$Pressure, x = MaximaRows$Relative_time)
}

#' Execute the localMaxima Function to find minima
#'
#' This function uses the localMaxima function to assess the ingested data table but first manipulates data (mulitply by -1) to instead find minima
#'
#' @param x Datatable of relative time x relative pressure
#'
#' @return MaximaRows -- Dataset of local minima in ingested dataset
#' @export calcLocalMin
#'
#' @examples calcLocalMin(data2)
calcLocalMin <- function(x) {
  data4 <- x
  x <- x[order(Relative_time)]
  x$row_num <- seq.int(nrow(x))
  data4$Pressure <- x$Pressure*-1
  LocalMinima <- localMaxima(data4$Pressure)
  MinimaRows <<- x[x$row_num %in% LocalMinima, ]

  plot(y = MinimaRows$Pressure, x = MinimaRows$Relative_time)
}

#' Clean MaximaRows output to isolate valid systolic BP
#'
#' local maxima for a pressure wave will find systolic BP but also a point into a dichroic notch which this function will aim to remove
#' Note that this local value removal code serves limited function now with the new data extraction method but was left in to prevent any potential extraneous values

#'
#' @param x Dataset of local maxima in ingested dataset
#'
#' @return FinalMaxima3 -- Dataset of cleaned local maxima (nearly completely diastolic BP) in ingested dataset
#' @export localvalremoveMax
#'
#'
#' @examples localvalremoveMax(MaximaRows)
localvalremoveMax <- function(x) {
  ###Dropped Code###
  #setorder(x, cols = -"Pressure")
  #x$Relative_time<- round_any(x$Relative_time, accuracy = 2, f = ceiling)
  #setorder(x, cols = -"Pressure")
  #FinalMaxima <- distinct(x, Relative_time, .keep_all=TRUE)

  setorder(x, cols = "Relative_time")
  FinalMaxima2 <- mutate(x, difcheck = Pressure + -lag(Pressure)) #calculate a new column to find difference in pressure between adjacent two points (to reveal where pressure jump is high and, thus, likely part of dichroic notch)
  FinalMaxima2[is.na(FinalMaxima2)] <- 0 #recode NA to 0
  FinalMaxima3 <- FinalMaxima2[FinalMaxima2$difcheck >= -100 & FinalMaxima2$difcheck <= 100, ] #select only columns where change in pressure isn't >100

  FinalMaxima31 <- mutate(FinalMaxima3, difcheck = Pressure + -lag(Pressure)) #cycling to remove clusters of aberrant data
  FinalMaxima31[is.na(FinalMaxima31)] <- 0
  FinalMaxima32 <- FinalMaxima31[FinalMaxima31$difcheck <= 100 & FinalMaxima31$difcheck >= -100, ]

  FinalMaxima33 <- mutate(FinalMaxima32, difcheck = Pressure + -lag(Pressure))
  FinalMaxima33[is.na(FinalMaxima33)] <- 0
  FinalMaxima4 <<- FinalMaxima33[FinalMaxima33$difcheck <= 100 & FinalMaxima33$difcheck >= -100, ]

  plot(y = FinalMaxima4$Pressure, x = FinalMaxima4$Relative_time)
  }

#' Clean Minima output to isolate valid diastolic BP
#'
#' local maxima (w/ -1 manipulation) for a pressure wave will find diastolic BP but also a point into a dichroic notch which this function will aim to remove
#' Note that this local value removal code serves limited function now with the new data extraction method but was left in to prevent any potential extraneous values
#'
#' @param x Dataset of local maxima in ingested dataset
#'
#' @return FinalMaxima3 -- Dataset of cleaned local maxima in ingested dataset
#' @export localvalremoveMin
#'
#' @examples localvalremoveMin(MinimaRows)
localvalremoveMin <- function(x) {
  ###Dropped Code###
  #x$Relative_time<- round_any(x$Relative_time, 2, f = ceiling)
  #setorder(x, cols = "Pressure")

  #FinalMinima <- distinct(x, Relative_time, .keep_all=TRUE)

  setorder(x, cols = "Relative_time")  #reset order based on relative time
  FinalMinima2 <- mutate(x, difcheck = Pressure + -lag(Pressure)) #calc a new column to find difference in pressure between adjacent two points (to reveal where pressure jump is high and, thus, likely part of dichroic notch)
  FinalMinima2[is.na(FinalMinima2)] <- 0
  FinalMinima3 <- FinalMinima2[FinalMinima2$difcheck <= 100 & FinalMinima2$difcheck >= -100, ]

  FinalMinima31 <- mutate(FinalMinima3, difcheck = Pressure + -lag(Pressure)) #cycling to remove clusters of abberant data
  FinalMinima31[is.na(FinalMinima31)] <- 0
  FinalMinima32 <- FinalMinima31[FinalMinima31$difcheck <= 100 & FinalMinima31$difcheck >= -100, ]

  FinalMinima33 <- mutate(FinalMinima32, difcheck = Pressure + -lag(Pressure))
  FinalMinima33[is.na(FinalMinima33)] <- 0
  FinalMinima4 <<- FinalMinima33[FinalMinima33$difcheck <= 100 & FinalMinima33$difcheck >= -100, ]

  plot(y = FinalMinima4$Pressure, x = FinalMinima4$Relative_time)
}

#' Calculate Pulse wave and Fit non-parametric curve
#'
#' This function calculates a non-parametric curve (spline) for the systolic and then diastolic BP data tables, predicts a set of values for each, and uses the predicted values to calculate a pulse pressure for which it then outputs a nonparametric curve
#'
#' @param x data table of systolic maxima
#' @param y data table of diastolic minima
#' @param n string used to name the output png
#'
#' @return predpulsewave -- data table of predicted pulse pressure values
#' @export nonparam
#'
#' @examples nonparam(FinalMaxima4, FinalMinima4, name)
nonparam <- function(x, y, n) {
  a <- min(x$Relative_time)
  b <- max(x$Relative_time)

  spline <- smooth.spline(x = y$Relative_time, y = y$Pressure, df = 4)
  newx <- seq(a, b, by = 1)
  newvals <- predict(spline, x = newx)
  newvals <- as.data.table(newvals)
  setnames(newvals, 'x', 'Relative_time')
  setnames(newvals, 'y', 'Diastolic_Minima')

  spline <- smooth.spline(x = x$Relative_time, y = x$Pressure, df = 6)
  newx <- seq(a, b, by = 1)
  newvals2 <<- predict(spline, x = newx)
  newvals2 <<- as.data.table(newvals2)
  setnames(newvals2, 'x', 'Relative_time')
  setnames(newvals2, 'y', 'Systolic_Maxima')

  newvals2$Diastolic_Minima <<- newvals$Diastolic_Minima
  newvals2$Pulse_Wave <<- newvals2$Systolic_Maxima - newvals2$Diastolic_Minima

  predpulsewave <<- newvals2

  #name <- paste0("PulseWave_", n, ".png")
  #png(file=name, height = 500, width = 600, point=16)
  #plot(newvals2$Pulse_Wave ~ newvals2$Relative_time, type = 'l', xlab = "Relative Time", ylab = "Pulse Wave")
  #dev.off()
}


