#' Calculate first derivative of the pulse wave
#'
#' @param x data table of predicted pulse pressure values
#' @param n string used to name the output png
#'
#' @return dapulsewave -- data table of predicted pulse pressure values with the addition of first derivative (da) values
#' @return FirstDev_n.png
#'
#' @import Hmisc
#'
#' @examples firstdev(predpulsewave, name)
firstdev <- function(x, n) {
  x <- mutate(x, da = Pulse_Wave + -Lag(Pulse_Wave, shift = 1))
  x[is.na(x)] <- 0
  x <- x[-c (1), ]
  dapulsewave <<- x
  name <- paste0("FirstDev_", n, ".png")
  png(file=name, height = 500, width = 600, point=16)
  plot(x$da ~ x$Relative_time, type = 'l', xlab = "Relative Time", ylab = "First Derivative Pulse Wave", xlim=c(0, 250), ylim=c(-1.5, 4))
  dev.off()
}

