#' Find minimum points of first derivative
#'
#' Finds the inflection points of the pulse pressure graph to be used in iCe
#'
#' @param x data table of predicted pulse pressure values which includes first derivatives
#'
#' @return inflection_points -- two lowest amplitude minima of the first derivative graph
#' @export inflecpoints
#'
#' @examples inflecpoints(dapulsewave)
inflecpoints <- function(x) {
  a <- min(x$Relative_time)
  b <- max(x$Relative_time)

  x$da <- x$da*-1
  dalocalmin <- localMaxima(x$da)
  x$row_num <- seq.int(nrow(x))
  daminima <- x[x$row_num %in% dalocalmin, ]
  setorder(daminima, cols = "da")
  inflection_point <- tail(daminima, n=2)

  localmax <- localMaxima(x$Pulse_Wave)
  lmax <- x[x$row_num %in% localmax, ]
  setorder(lmax, cols = "Pulse_Wave")
  max <- head(lmax, n=1)

  x$Pulse_Wave <- x$Pulse_Wave*-1
  localmin <- localMaxima(x$Pulse_Wave)
  lmin <- x[x$row_num %in% localmin, ]
  setorder(lmin, cols = "Pulse_Wave")
  min <- tail(lmin, n=1)

  inflection_points <- rbind(inflection_point,max,min)
  inflection_points <<- filter(inflection_points, Relative_time != a & Relative_time != b)
}

#' Make a ggplot overlay for client viewing
#'
#' @param x pre-exercise data
#' @param y post-exercise data
#' @param n string for naming
#' @param l string for Pressure minima
#' @param o string for Pressure maxima
#' @param v string for Time minima
#' @param z string for Time maxima
#'
#' @return ClientGraph_test.png
#' @export Clientgraph
#'
#' @import png
#' @import grid
#' @import ggpubr
#'
#' @examples Clientgraph(Pre, Post, "name", "0", "600", "0", "300")
Clientgraph <- function(x, y, n, l, o, v, z) {
  min <- as.numeric(l)
  max <- as.numeric(o)
  tmin <- as.numeric(v)
  tmax <- as.numeric(z)

  wd <- getwd()
  name2 <- paste0("ClientGraph_", n, ".png")
  x$Time <- x$Relative_time/2.16 #multiplier is to turn relative units to seconds calculated from a reference screenshot
  y$Time <- y$Relative_time/2.16

  img <- readPNG("iCe_vector.png")
  g2 <- matrix(rgb(img[,,1],img[,,2],img[,,3],img[,,4] * 0.15), nrow=dim(img)[1]) ## you can change 0.5 to change the alpa
  g <- rasterGrob(g2, interpolate=TRUE)
  #ref <- readPNG("refGraph.png")
  #ref2 <- rasterGrob(ref, interpolate=TRUE)

  ggplot(x, aes(x = Time, y = Pulse_Wave) ) +
    annotation_custom(g, xmin=(tmax-.95*tmax), xmax=(0.95*tmax), ymin=(max-0.95*max), ymax=(0.95*max)) +
    #annotation_custom(ref2, xmin=210, xmax=Inf, ymin=-Inf, ymax=100)+
    geom_point(color= "#197E9A") +
    geom_point(data=x[x$min == "1",],color="#002f65",size=3) +
    geom_point(data=x[x$intslope == "1",],color="#2dbfc6") +
    geom_point(data = y, color="#cd2400") +
    geom_point(data=y[y$min == "1",],color="#8b0000",size=3) +
    geom_point(data=y[y$intslope == "1",],color="#FF4F00") +
    #geom_hline(yintercept=c(125, 200), linetype='dashed', color=c('red', 'red')) +
    xlim(tmin, tmax) +
    ylim(min, max) +
    theme_classic() +
    xlab("Time (seconds)")+
    ylab("Pulse Pressure")+
    theme(
      axis.title.x = element_text(size = 16, face="bold"),
      axis.text.x = element_text(size = 14),
      axis.title.y = element_text(size = 16, face="bold"),
      axis.text.y = element_blank(),
      axis.ticks.y = element_blank(),
      #plot.background = element_rect(fill = "transparent", color = NA),
      #panel.background = element_rect(fill = "transparent"),
      legend.position="none")

  ggsave(
    name2,
    plot = last_plot(),
    path = wd,
    scale = 1,
    width = 6.03,
    height = 7.04
    #bg = "transparent"
  )
}
